import json, os, re, random, chess
rules=json.load(open('/app/re.json'))
print('pairs', len(rules), 'bytes', os.path.getsize('/app/re.json'))
def run_solution(fen):
    for pattern, repl in rules:
        fen = re.sub(pattern, repl, fen)
    return [" ".join(x.split(' ')[:-2]) for x in fen.split('\n')]
random.seed(12345)
boards=[]
while len(boards) < 10:
    b=chess.Board()
    for _ in range(random.randint(0,40)):
        if not list(b.legal_moves):
            break
        b.push(random.choice(list(b.legal_moves)))
    if b.turn==chess.WHITE and not b.is_game_over():
        boards.append(b)
for i,b in enumerate(boards,1):
    fen=b.fen()
    got=set(run_solution(fen))
    exp=set()
    for m in b.legal_moves:
        if m.promotion and m.promotion!=chess.QUEEN: continue
        c=b.copy(); c.push(m)
        exp.add(" ".join(c.fen().split(' ')[:-2]))
    print(f'{i}: {"ok" if got==exp else "FAIL"} got={len(got)} exp={len(exp)} {fen}')
